// Parse Lightspeed portfolio companies from Consider page HTML
// HTML structure: job-boards-company-item divs with name, description, tags
const items = $input.all();
const html = String(items[0]?.json?.data || items[0]?.json || '');
const results = [];
const seen = new Set();
const today = new Date().toISOString().split('T')[0];
const vcName = 'Lightspeed';

// Extract each company card block
// Pattern: <div ... class="job-boards-company-item">...entire card...</div>
const cardPattern = /<div[^>]*class="[^"]*job-boards-company-item[^"]*"[^>]*>([\s\S]*?)(?=<div[^>]*class="[^"]*job-boards-company-item|$)/gi;

let cardMatch;
while ((cardMatch = cardPattern.exec(html)) !== null) {
  const cardHtml = cardMatch[0];

  // Extract company name from h2.job-boards-company-name
  const nameMatch = cardHtml.match(/<h2[^>]*class="[^"]*job-boards-company-name[^"]*"[^>]*>([^<]+)<\/h2>/i);
  if (!nameMatch) continue;

  const name = nameMatch[1].trim();
  if (!name || name.length < 2) continue;

  const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
  if (seen.has(key)) continue;
  seen.add(key);

  // Extract description from div.job-boards-company-description
  const descMatch = cardHtml.match(/<div[^>]*class="[^"]*job-boards-company-description[^"]*"[^>]*>([^<]+)<\/div>/i);
  const description = descMatch ? descMatch[1].trim() : `${name} - Lightspeed portfolio company`;

  // Extract tags (stage, employee count) from span.job-boards-company-tag
  const tagPattern = /<span[^>]*class="[^"]*job-boards-company-tag[^"]*"[^>]*>([^<]+)<\/span>/gi;
  const tags = [];
  let tagMatch;
  while ((tagMatch = tagPattern.exec(cardHtml)) !== null) {
    tags.push(tagMatch[1].trim());
  }

  // Parse stage and employee count from tags
  let stage = '';
  let employees = '';
  for (const tag of tags) {
    const tagLower = tag.toLowerCase();
    if (tagLower.includes('seed') || tagLower.includes('series') || tagLower.includes('growth')) {
      stage = tag;
    } else if (tagLower.includes('employee') || /^\d+[\s\u2013\-]+\d+$/.test(tag)) {
      employees = tag;
    }
  }

  results.push({
    json: {
      'Company Name': name,
      'VC Firm': vcName,
      'Company Description': description,
      'Company URL': '',
      'Stage': stage,
      'Employee Count': employees,
      'Status': 'New',
      'First Seen Date': today,
      'Source': 'VC Portfolio'
    }
  });
}

if (results.length === 0) {
  // Debug: return info about what we found
  const hasCompanyItems = html.includes('job-boards-company-item');
  const hasCompanyNames = html.includes('job-boards-company-name');
  return [{ json: { _empty: true, _message: 'No companies found from Lightspeed', vcName, htmlLength: html.length, hasCompanyItems, hasCompanyNames, sampleHtml: html.substring(0, 500) } }];
}

return results;
